function onYouTubeIframeAPIReady(){window.YoutubePlayerScriptLoaded=!0}function onPlayerReady(e){e.target.playVideo()}BX.Aspro.Utils.readyDOM((()=>{BX.bindDelegate(document,"click",{class:"_youtube-video"},(function(){const e=this?.dataset?.videoId;if(!e)return;if(!window.YoutubePlayerScriptLoaded&&!window.YoutubeReadyToLoadScript){window.YoutubeReadyToLoadScript=!0;const e=document.createElement("script");e.src="https://www.youtube.com/iframe_api";const t=document.getElementsByTagName("script")[0];t.parentNode.insertBefore(e,t)}let t=setInterval((()=>{if(window.YoutubePlayerScriptLoaded){new YT.Player(`youtube-player-id-${e}`,{videoId:e,events:{onReady:onPlayerReady}});clearInterval(t)}}),100);this.classList.add("videoloaded")}))}));